"use client";

import { motion } from "framer-motion";
import { useState } from "react";

// Data Structure perfectly modeled for a High-Availability DBA infrastructure
const nodes = [
  { id: "lb", label: "HA Proxy / Cloud LB", details: "Ingress Router & Traffic Distribution", x: 150, y: 150 },
  { id: "write_master", label: "Primary Write Node", details: "MySQL 8.0 RDS Cluster (Master)", x: 450, y: 70 },
  { id: "read_rep_1", label: "Read Replica A", details: "Async Replica (Region us-east)", x: 400, y: 250 },
  { id: "read_rep_2", label: "Read Replica B", details: "Async Replica (Region eu-west)", x: 500, y: 250 },
  { id: "cache", label: "Redis Sentinel", details: "In-Memory Session & Query Cache", x: 300, y: 160 },
];

const edges = [
  { source: "lb", target: "cache" },
  { source: "cache", target: "write_master" },
  { source: "lb", target: "read_rep_1" },
  { source: "lb", target: "read_rep_2" },
  { source: "write_master", target: "read_rep_1", dashed: true },
  { source: "write_master", target: "read_rep_2", dashed: true },
];

export default function SystemDiagram() {
  const [hoveredNode, setHoveredNode] = useState<string | null>(null);

  const getNodeCoords = (id: string) => nodes.find(n => n.id === id);

  return (
    <div className="relative w-full max-w-4xl mx-auto h-[400px] bg-black border border-white/20 p-4 overflow-hidden group font-mono">
      {/* Background Grid */}
      <div className="absolute inset-0 opacity-[0.05] bg-[linear-gradient(to_right,#ffffff_1px,transparent_1px),linear-gradient(to_bottom,#ffffff_1px,transparent_1px)] bg-[size:4vw_4vw] pointer-events-none" />

      {/* Title */}
      <div className="absolute top-4 left-4 text-xs text-white/40 tracking-[0.3em] uppercase flex flex-col">
        <span>Topology_Map</span>
        <span className="text-[8px]">Active Routing...</span>
      </div>

      <svg className="absolute inset-0 w-full h-full" style={{ zIndex: 1 }}>
        <defs>
          <linearGradient id="line-grad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="rgba(255,255,255,0.1)" />
            <stop offset="100%" stopColor="rgba(255,255,255,0.8)" />
          </linearGradient>
        </defs>
        {edges.map((edge, i) => {
          const source = getNodeCoords(edge.source);
          const target = getNodeCoords(edge.target);
          if (!source || !target) return null;

          return (
            <motion.line
              key={i}
              x1={source.x}
              y1={source.y}
              x2={target.x}
              y2={target.y}
              stroke="url(#line-grad)"
              strokeWidth="1.5"
              strokeDasharray={edge.dashed ? "4,4" : "0"}
              initial={{ pathLength: 0, opacity: 0 }}
              whileInView={{ pathLength: 1, opacity: 0.6 }}
              transition={{ duration: 1.5, delay: i * 0.2 }}
            />
          );
        })}
      </svg>

      {nodes.map((node, i) => (
        <motion.div
          key={node.id}
          className="absolute transform -translate-x-1/2 -translate-y-1/2 cursor-crosshair z-10"
          style={{ left: node.x, top: node.y }}
          initial={{ scale: 0, opacity: 0 }}
          whileInView={{ scale: 1, opacity: 1 }}
          transition={{ duration: 0.5, delay: i * 0.2, type: "spring" }}
          onMouseEnter={() => setHoveredNode(node.id)}
          onMouseLeave={() => setHoveredNode(null)}
          whileHover={{ scale: 1.05 }}
        >
          {/* Brutalist Node Box */}
          <div className="w-28 h-20 bg-black border border-white/30 flex flex-col items-center justify-center shadow-[0_0_15px_rgba(255,255,255,0.05)] transition-colors hover:bg-white/5 hover:border-white relative">
            <span className="absolute top-1 left-1 w-1.5 h-1.5 bg-white/60 animate-pulse" />
            <span className="text-white text-[10px] font-bold text-center leading-tight px-2 uppercase tracking-widest">{node.label}</span>
          </div>
          
          {hoveredNode === node.id && (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="absolute top-full mt-4 w-56 left-1/2 transform -translate-x-1/2 bg-black border border-white/50 text-white p-4 shadow-2xl z-50 pointer-events-none flex flex-col"
            >
              <span className="text-[10px] uppercase tracking-widest border-b border-white/20 pb-2 mb-2 text-white/50">Node Metadata</span>
              <span className="text-xs">{node.details}</span>
              <span className="text-[8px] mt-4 text-white/30 tracking-[0.2em]">LATENCY: {(Math.random() * 2 + 1).toFixed(2)}ms</span>
            </motion.div>
          )}
        </motion.div>
      ))}

      {/* Animated data packets */}
      <svg className="absolute inset-0 w-full h-full pointer-events-none" style={{ zIndex: 2 }}>
        {edges.map((edge, i) => {
          const source = getNodeCoords(edge.source);
          const target = getNodeCoords(edge.target);
          if (!source || !target || edge.dashed) return null; // Don't animate dashed rep links as heavily
          return (
            <motion.rect
              key={`packet-${i}`}
              width="4"
              height="4"
              fill="#ffffff"
              initial={{ x: source.x - 2, y: source.y - 2, opacity: 0 }}
              animate={{ x: target.x - 2, y: target.y - 2, opacity: [0, 1, 0] }}
              transition={{ duration: 1.2, repeat: Infinity, delay: i * 0.4, ease: "linear" }}
            />
          );
        })}
      </svg>
    </div>
  );
}
